vector<int> scheduleTasks(vector<int>& taskDeadlines, vector<int>& taskRewards) {

    int n = taskDeadlines.size();

    vector<pair<int,int>> jobs;
    int maxDeadline = 0;

    for(int i=0;i<n;i++){
        jobs.push_back({taskRewards[i], taskDeadlines[i]});
        maxDeadline = max(maxDeadline, taskDeadlines[i]);
    }

    sort(jobs.begin(), jobs.end(), greater<>());

    vector<int> parent(maxDeadline+1);
    for(int i=0;i<=maxDeadline;i++)
        parent[i]=i;

    function<int(int)> find = [&](int x){
        if(parent[x]==x) return x;
        return parent[x]=find(parent[x]);
    };

    int count=0,total=0;

    for(auto &job:jobs){
        int slot=find(job.second);

        if(slot>0){
            parent[slot]=find(slot-1);
            count++;
            total+=job.first;
        }
    }

    return {count,total};
}

