int compare(const void* a, const void* b){
    return ((Task*)b)->reward - ((Task*)a)->reward;
}


int* scheduleTasks(int* taskDeadlines, int* taskRewards, int n, int* returnSize){

    Task* tasks = (Task*)malloc(sizeof(Task) * n);
    int maxDeadline = 0;

    for(int i = 0; i < n; i++){
        tasks[i].reward = taskRewards[i];
        tasks[i].deadline = taskDeadlines[i];
        if(taskDeadlines[i] > maxDeadline)
            maxDeadline = taskDeadlines[i];
    }

    qsort(tasks, n, sizeof(Task), compare);

    int* parent = (int*)malloc(sizeof(int) * (maxDeadline + 1));
    for(int i = 0; i <= maxDeadline; i++)
        parent[i] = i;

    int count = 0, total = 0;

    for(int i = 0; i < n; i++){

        int slot = find(tasks[i].deadline, parent);

        if(slot > 0){
            parent[slot] = find(slot - 1, parent);
            count++;
            total += tasks[i].reward;
        }
    }

    int* res = (int*)malloc(sizeof(int) * 2);
    res[0] = count;
    res[1] = total;
    *returnSize = 2;

    free(tasks);
    free(parent);

    return res;
}

