private int find(int x, int[] parent){
    if(parent[x] == x)
        return x;

    return parent[x] = find(parent[x], parent);
}

public int[] scheduleTasks(int[] taskDeadlines, int[] taskRewards) {

    int n = taskDeadlines.length;
    int maxDeadline = 0;

    // Store tasks as {reward, deadline}
    int[][] tasks = new int[n][2];

    for(int i = 0; i < n; i++){
        tasks[i][0] = taskRewards[i];
        tasks[i][1] = taskDeadlines[i];
        maxDeadline = Math.max(maxDeadline, taskDeadlines[i]);
    }

    // Sort by reward DESC
    Arrays.sort(tasks, (a, b) -> b[0] - a[0]);

    // DSU parent array
    int[] parent = new int[maxDeadline + 1];
    for(int i = 0; i <= maxDeadline; i++)
        parent[i] = i;

    int count = 0;
    int totalReward = 0;

    for(int[] task : tasks){

        int availableSlot = find(task[1], parent);

        if(availableSlot > 0){

            // occupy slot
            parent[availableSlot] = find(availableSlot - 1, parent);

            count++;
            totalReward += task[0];
        }
    }

    return new int[]{count, totalReward};
}

