function scheduleTasks(taskDeadlines, taskRewards) {

    const jobs = taskRewards.map((r,i)=>[r, taskDeadlines[i]])
                            .sort((a,b)=>b[0]-a[0]);

    const maxDeadline = Math.max(...taskDeadlines);

    const parent = Array.from({length:maxDeadline+1},(_,i)=>i);

    function find(x){
        if(parent[x]!==x)
            parent[x]=find(parent[x]);
        return parent[x];
    }

    let count=0,total=0;

    for(const [reward,deadline] of jobs){

        const slot=find(deadline);

        if(slot>0){
            parent[slot]=find(slot-1);
            count++;
            total+=reward;
        }
    }

    return [count,total];
}
